CREATE OR REPLACE FUNCTION fpa_acc_lon_count_bydate (as_longr char,adt_date_fr timestamp(0),adt_date_to timestamp(0)) RETURNS integer AS $body$
DECLARE

  li_count integer;

BEGIN
  select count(sc_lon_m_contract.loan_contract_no) into STRICT li_count
  from sc_lon_m_contract
  , sc_lon_m_loan_card
  , sc_lon_m_rule
  where (sc_lon_m_contract.loan_contract_no = sc_lon_m_loan_card.loan_contract_no)
  and (sc_lon_m_contract.loan_type = sc_lon_m_rule.loan_type)
  and (sc_lon_m_contract.begining_of_contract between adt_date_fr and adt_date_to)
  and (sc_lon_m_rule.loan_group_code = as_longr);
  return li_count;
exception when others then CALL spa_dberror('fpa_acc_lon_count_bydate');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
